func (imp *importResolver) shouldImport(s string) bool {
	if !strings.HasPrefix(s, importIdentifier) {
		return false
	}
	if strings.Contains(s, "url(") {
		return false
	}

	m := shouldImportRe.FindStringSubmatch(s)
	if m == nil {
		return false
	}

	if len(m) != 3 {
		return false
	}

	if tailwindImportExclude(m[1]) {
		return false
	}

	return true
}
